#include<cstdio>
#include<queue>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
#define grep(b,c) for(int c(head[b]);c;c=nxt[c])
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
template<typename T> inline T max(const T&x,const T&y){return x<y?y:x;}
typedef std::pair<int,int> pii;
const int N=5e5+10;std::priority_queue<pii> h;
int head[N],des[N<<1],nxt[N<<1],cgt,n,m,deg[N],f[N],g[N],P[N],cpt,loc[N],stk[N],top,Smx[N],Tmx[N];
inline void ins(int y,int x){nxt[++cgt]=head[x];des[head[x]=cgt]=y;++deg[y];}

int main()
{
	n=read();m=read();rep(1,m,i)ins(read(),read());
	rep(1,n,i)if(!deg[i])stk[++top]=i;
	while(top)
	{
		int u=stk[top--];P[++cpt]=u;loc[u]=cpt;
		grep(u,i)
		{
			int v=des[i];if(!(--deg[v]))stk[++top]=v;
			f[v]=max(f[v],f[u]+1);
		}
	}
	drep(n,1,i){int u=P[i];grep(u,i)g[u]=max(g[u],g[des[i]]+1);}
	rep(1,n,i)Smx[i]=max(Smx[i-1],f[P[i]]);
	drep(n,1,i)Tmx[i]=max(Tmx[i+1],g[P[i]]);
	int ans=Tmx[2],idx=P[1];
	rep(1,n,i)
	{
		int u=P[i];
		while(!h.empty()&&h.top().second<=i)h.pop();
		int tmp=max(Smx[i-1],Tmx[i+1]);if(!h.empty())tmp=max(tmp,h.top().first);
		if(tmp<ans)ans=tmp,idx=u;
		grep(u,i){int v=des[i];h.push({f[u]+g[v]+1,loc[v]});}
	}
	printf("%d %d\n",idx,ans);
}
